patch:
---
 drivers/acpi/scan.c |   24 +++++++++++++++++-------
 1 file changed, 17 insertions(+), 7 deletions(-)

Index: linux-2.6/drivers/acpi/scan.c
===================================================================
--- linux-2.6.orig/drivers/acpi/scan.c
+++ linux-2.6/drivers/acpi/scan.c
@@ -1322,16 +1322,26 @@ end:

 static void acpi_bus_add_power_resource(acpi_handle handle)
 {
-	struct acpi_bus_ops ops = {
-		.acpi_op_add = 1,
-		.acpi_op_start = 1,
-	};
+	//struct acpi_bus_ops ops = {
+	//	.acpi_op_add = 1,
+	//	.acpi_op_start = 1,
+	//};
 	struct acpi_device *device = NULL;

 	acpi_bus_get_device(handle, &device);
-	if (!device)
-		acpi_add_single_object(&device, handle, ACPI_BUS_TYPE_POWER,
-					ACPI_STA_DEFAULT, &ops);
+	if (!device) {
+		struct acpi_buffer path = {ACPI_ALLOCATE_BUFFER, NULL};
+		int result;
+
+		result = acpi_get_name(handle, ACPI_FULL_PATHNAME, &path);
+		if (!result) {
+			pr_info("%s: %s\n", __func__, (char*)path.pointer);
+			kfree(path.pointer);
+		}
+
+		//acpi_add_single_object(&device, handle, ACPI_BUS_TYPE_POWER,
+		//			ACPI_STA_DEFAULT, &ops);
+	}
 }

 static int acpi_bus_type_and_status(acpi_handle handle, int *type,
---
 drivers/acpi/scan.c |    4 +++-
 1 file changed, 3 insertions(+), 1 deletion(-)

Index: linux-2.6/drivers/acpi/scan.c
===================================================================
--- linux-2.6.orig/drivers/acpi/scan.c
+++ linux-2.6/drivers/acpi/scan.c
@@ -882,7 +882,9 @@ static int acpi_bus_get_power_flags(stru
 			device->power.flags.power_resources = 1;
 			ps->flags.valid = 1;
 			for (j = 0; j < ps->resources.count; j++)
-				acpi_bus_add_power_resource(ps->resources.handles[j]);
+				if (device->handle != ps->resources.handles[j])
+					acpi_bus_add_power_resource(
+						ps->resources.handles[j]);
 		}

 		/* Evaluate "_PSx" to see if we can do explicit sets */
---
 drivers/acpi/scan.c |    4 ++++
 1 file changed, 4 insertions(+)

Index: linux-2.6/drivers/acpi/scan.c
===================================================================
--- linux-2.6.orig/drivers/acpi/scan.c
+++ linux-2.6/drivers/acpi/scan.c
@@ -943,6 +943,10 @@ static int acpi_bus_get_flags(struct acp
 	if (ACPI_SUCCESS(status))
 		device->flags.lockable = 1;

+	/* Power resources cannot be power manageable. */
+	if (device->device_type == ACPI_BUS_TYPE_POWER)
+		return 0;
+
 	/* Presence of _PS0|_PR0 indicates 'power manageable' */
 	status = acpi_get_handle(device->handle, "_PS0", &temp);
 	if (ACPI_FAILURE(status))
